var x = msg.payload;
var timeStop;
var timeStart;
var isTimingStarted = false;
var previousX1 = flow.get("previousX1");
var difstart = flow.get("T2");
var difstop = flow.get("T1");

if (x !== previousX1) {
    if ((x === 0 && previousX1 === 1) || (x === 1 && previousX1 === 0)) {
        if (x === 0) {
            isTimingStarted = true;
            timeStop = new Date().getTime();
            timeStop += 7 * 60 * 60 * 1000;
            var dateObj = new Date(timeStop);
            var hours = dateObj.getHours();
            var minutes = dateObj.getMinutes();
            var year = dateObj.getFullYear();
            var month = dateObj.getMonth() + 1;
            var day = dateObj.getDate();
            var formattedTime = hours.toString().padStart(2, '0') + ':' + minutes.toString().padStart(2, '0');
            var formattedDate = year.toString().padStart(4, '0') + '-' + month.toString().padStart(2, '0') + '-' + day.toString().padStart(2, '0');
            flow.set('T1', timeStop);
            flow.set('sum1', 0);
            msg.payload = "\nLine Name: SCAN H2" +
                "\nLocation Name: Compressor" +
                "\nStatus Location: STOP" +
                "\nDate: " + formattedDate +
                "\nTime Stop: " + formattedTime;

        } else if (x === 1) {
            isTimingStarted = false;
            timeStart = new Date().getTime();
            timeStart += 7 * 60 * 60 * 1000;
            var dateObj = new Date(timeStart);
            var hours = dateObj.getHours();
            var minutes = dateObj.getMinutes();
            var year = dateObj.getFullYear();
            var month = dateObj.getMonth() + 1;
            var day = dateObj.getDate();
            var formattedTime = hours.toString().padStart(2, '0') + ':' + minutes.toString().padStart(2, '0');
            var formattedDate = year.toString().padStart(4, '0') + '-' + month.toString().padStart(2, '0') + '-' + day.toString().padStart(2, '0');
            flow.set('T2', timeStart);
            var timeDifferenceInMillis = difstop - difstart  ;
            var diffTime = Math.floor(timeDifferenceInMillis/60000)
            var formattedMinutes = diffTime.toString().padStart(1, '0');
            flow.set('sum1', formattedMinutes);

            msg.payload = "\nLine Name: SCAN H2" +
                "\nLocation Name: Compressor" +
                "\nStatus Location: START" +
                "\nDate: " + formattedDate +
                "\nTime Start: " + formattedTime +
                "\nDuration: " + formattedMinutes + " m";
        }
        flow.set("previousX1", x);
        return msg;
    }
}
