const data = msg.payload;

if (!Array.isArray(data) || data.length === 0) {
    return null;
}

// ฟังก์ชันสำหรับจัดการข้อมูลให้ปลอดภัย
const clean = (val) => {
    if (val === null || val === undefined || val === '') return 'NULL';
    // ลบช่องว่าง และจัดการเครื่องหมาย ' เพื่อป้องกัน Syntax พัง
    let safeVal = String(val).trim().replace(/'/g, "''");
    return `'${safeVal}'`;
};

const rows = data.map((item) => {
    // แนะนำให้ครอบ clean() ทุกฟิลด์ที่เป็นตัวอักษร 
    // และเช็คว่า JOID กับ TIMESTAMP เป็นตัวเลขจริงๆ หรือไม่ (ถ้าไม่แน่ใจให้ใช้ clean ครอบไปเลย)
    return `SELECT ${item.JOID}, ${clean(item.JOB_ORDER_NO)}, ${clean(item.MODEL)}, ${clean(item.BATCH_NO)}, ${item.TIMESTAMP}, 'SYSTEM-FETCH', NULL, NULL, GETDATE()`;
});

let sql = `INSERT INTO MD_QC_HOLD_BATCH_NO (JOID, JOB_ORDER_NO, MODEL, BATCH_NO, TIMESTAMP, HOLD_BY, ENDDATE, EDITDATE, LOGDATE) \n`;
sql += rows.join('\n UNION ALL \n');

// *** จุดสำคัญ ***
// ตรวจสอบว่า MSSQL Node ของคุณรับค่าจาก msg.payload หรือ msg.sql
// จากภาพ debug คุณตั้งชื่อว่า msg.sql ลองเปลี่ยนมาส่งทั้งคู่เพื่อความชัวร์ครับ
msg.payload = sql;
msg.sql = sql;

return msg;

