const formatDatetime = (dt) => {
  const addLenght = (num) => (num < 10 ? "0" + num : num);
  const now = new Date(dt);
  const years = now.getFullYear();
  const month = addLenght(now.getMonth() + 1);
  const date = addLenght(now.getDate());

  const hours = addLenght(now.getHours());
  const minutes = addLenght(now.getMinutes());
  const seconds = addLenght(now.getSeconds());
  const gettime = parseInt(now.getTime());

  const getDate = `${years}-${month}-${date}`;
  const getTime = `${hours}:${minutes}:${seconds}`;
  const getDatetime = `${getDate} ${getTime}`;
  const getDatetimeLocal = `${years}-${month}-${date}T${hours}:${minutes}`;
  const getHour = `${hours}`;
  const getMinute = `${minutes}`;
  const getDateShow = `${date}-${month}-${years}`;
  const getDay = `${date}`;

  return { getDate, getTime, getDatetime, getDatetimeLocal, getHour, getMinute, getDateShow, getDay, gettime };
};

